function tryParseJson(value) {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  if (!trimmed.startsWith('{') && !trimmed.startsWith('[')) return value;
  try { return JSON.parse(trimmed); } catch (error) { return value; }
}

function looksLikeWrapper(value) {
  return Boolean(
    value &&
    typeof value === 'object' &&
    (
      value.content !== undefined ||
      value.message !== undefined ||
      value.data !== undefined ||
      value.response !== undefined ||
      value.output_text !== undefined ||
      value.text !== undefined
    )
  );
}

function collectText(value, depth = 0) {
  if (!value || depth > 6) return '';

  if (typeof value === 'string') {
    const parsed = tryParseJson(value);
    if (parsed !== value && looksLikeWrapper(parsed)) return collectText(parsed, depth + 1);
    return value;
  }

  if (Array.isArray(value)) {
    return value.map((entry) => collectText(entry, depth + 1)).filter(Boolean).join('\n');
  }

  if (Array.isArray(value.content)) {
    const text = value.content.map((part) => collectText(part, depth + 1)).filter(Boolean).join('\n');
    if (text) return text;
  }

  if (value.message && Array.isArray(value.message.content)) {
    const text = value.message.content.map((part) => collectText(part, depth + 1)).filter(Boolean).join('\n');
    if (text) return text;
  }

  for (const key of ['output_text', 'text', 'data', 'result', 'response']) {
    const text = collectText(value[key], depth + 1);
    if (text) return text;
  }

  return '';
}

function parseJsonText(text) {
  const fence = String.fromCharCode(96, 96, 96);
  const trimmed = String(text || '')
    .trim()
    .replace(new RegExp('^' + fence + 'json\\s*', 'i'), '')
    .replace(new RegExp('^' + fence + '\\s*', 'i'), '')
    .replace(new RegExp(fence + '$', 'i'), '')
    .trim();

  try {
    return JSON.parse(trimmed);
  } catch (error) {
    const start = trimmed.indexOf('{');
    const end = trimmed.lastIndexOf('}');
    if (start >= 0 && end > start) return JSON.parse(trimmed.slice(start, end + 1));
    throw error;
  }
}

