function kstDate(value = new Date()) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(value).reduce((acc, part) => {
    acc[part.type] = part.value;
    return acc;
  }, {});
  return parts.year + '-' + parts.month + '-' + parts.day;
}


function appendJsonLine(filePath, payload) {
  if (!filePath) return;
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.appendFileSync(filePath, JSON.stringify(payload) + '\n', 'utf8');
}

function safeTopicSlug(value) {
  return String(value || '')
    .replace(/[^a-zA-Z0-9가-힣_-]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 80) || Date.now().toString(36);
}

function uniqueDestination(filePath) {
  if (!fs.existsSync(filePath)) return filePath;
  const ext = path.extname(filePath);
  const base = filePath.slice(0, -ext.length);
  for (let index = 2; index < 100; index += 1) {
    const candidate = base + '-' + index + ext;
    if (!fs.existsSync(candidate)) return candidate;
  }
  return base + '-' + Date.now().toString(36) + ext;
}

function completeTopicQueueAfterUpload(data, status) {
  const youtube = data.youtube || {};
  // A run that was skipped because this exact topic was already published in an
  // earlier run must still release the topic, or the queue would retry it forever.
  const alreadyUploadedRecovery = data.upload_guard?.reason === 'already_uploaded'
    ? (data.upload_guard?.already_uploaded || null)
    : null;
  const publishedUrl = youtube.url && !youtube.skipped ? youtube.url : (alreadyUploadedRecovery?.url || null);
  if (!publishedUrl) return;

  const topicQueue = data.topic_queue || data.config?.topic_queue || null;
  const selected = topicQueue?.selected || null;
  const sourceFile = selected?.source_file;
  const usedDir = topicQueue?.used_dir || data.config?.topic_used_dir;
  const usedLogPath = topicQueue?.used_log_path || data.config?.topic_queue_used_log_path;

  if (!sourceFile || !usedDir || !fs.existsSync(sourceFile)) return;

  try {
    fs.mkdirSync(usedDir, { recursive: true });
    const stamp = new Date().toISOString().replace(/[:.]/g, '-');
    const ext = path.extname(sourceFile);
    const title = selected.title || data.pack?.hook_title || path.basename(sourceFile, ext);
    const destination = uniqueDestination(path.join(usedDir, stamp + '-' + safeTopicSlug(title) + ext));
    fs.renameSync(sourceFile, destination);

    topicQueue.consumed = true;
    topicQueue.consumed_file = destination;
    topicQueue.remaining_after = Math.max(0, Number(topicQueue.remaining_before || 1) - 1);
    topicQueue.completed_after_upload = true;

    appendJsonLine(usedLogPath, {
      id: selected.id || null,
      title,
      source: selected.source || 'topic_file',
      source_file: sourceFile,
      consumed_file: destination,
      rank_count: selected.rank_items?.length || selected.rank_count || null,
      status: 'picked_after_upload',
      upload_status: status,
      url: publishedUrl,
      date_kst: kstDate(),
      picked_at: selected.picked_at || null,
      consumed_at: new Date().toISOString(),
    });
  } catch (error) {
    topicQueue.consume_error = error.message;
  }
}

